index 9a16ca96db76..0ac3f6f25998 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -830,7 +830,7 @@ static Instruction *foldNoWrapAdd(BinaryOperator &Add,
   // (sext (X +nsw NarrowC)) + C --> (sext X) + (sext(NarrowC) + C)
   Constant *NarrowC;
   if (match(Op0,
-            m_OneUse(m_SExt(m_NSWAddLike(m_Value(X), m_Constant(NarrowC)))))) {
+            m_OneUse(m_SExtLike(m_NSWAddLike(m_Value(X), m_Constant(NarrowC)))))) {
     Value *WideC = Builder.CreateSExt(NarrowC, Ty);
     Value *NewC = Builder.CreateAdd(WideC, Op1C);
     Value *WideX = Builder.CreateSExt(X, Ty);
@@ -930,6 +930,19 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
       C2->isMinSignedValue() && C2->sext(Ty->getScalarSizeInBits()) == *C)
     return CastInst::Create(Instruction::SExt, X, Ty);

+  // add(zext nneg(add X, C1)), C2) --> sext X if C1 + C2 == 0
+  // This handles switch table index patterns like:
+  // add(zext nneg(add i8 X, 1)), -1) --> sext X
+  Constant *InnerC;
+  if (match(Op0, m_NNegZExt(m_Add(m_Value(X), m_Constant(InnerC))))) {
+    const APInt *InnerCVal;
+    if (match(InnerC, m_APInt(InnerCVal))) {
+      APInt InnerCWide = InnerCVal->sext(Ty->getScalarSizeInBits());
+      if (InnerCWide + *C == 0)
+        return CastInst::Create(Instruction::SExt, X, Ty);
+    }
+  }
+
   if (match(Op0, m_Xor(m_Value(X), m_APInt(C2)))) {
     // (X ^ signmask) + C --> (X + (signmask ^ C))
     if (C2->isSignMask())

